var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>지혜롭게 앞서가는 기업, 제프티 바이오테크의 프리미엄 프로모션 코스에 참여해 주신 데 대해 감사를 표합니다.</color>","JPN":"<color=#ffd34c>インテリジェントパイオニア企業、ジェフティ・バイオテックのプレミアムプロモーションコースへのご参加ありがとうございます。</color>","ENG":"<color=#ffd34c>Greetings from Jehuty Biotech, the leader in smart innovations. Thank you for participating in this premium promotion course.</color>","TWN":"<color=#ffd34c>機智領先的企業，感謝參與傑夫堤生物科技的高端促銷活動。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>자사는 침식체의 정신 제압 기술로 정체된 바이오 업계에 새로운 돌풍을 불러일으켰으며,</color>","JPN":"<color=#ffd34c>侵食体の精神制圧技術を利用し停滞していたバイオ業界に新たなセンセーションを巻き起こした弊社ですが</color>","ENG":"<color=#ffd34c>Jehuty Biotech is the developer of the psychological C.O. submission technology that has revived the stagnating bioengineering industry.</color>","TWN":"<color=#ffd34c>本公司以侵蝕體的精神壓制技術，在停滯的生物科技行業掀起了新的旋風，</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>최근에는 카운터의 복제에 성공하여 대 침식전의 패러다임을 바꾸기 시작했습니다.</color>","JPN":"<color=#ffd34c>このたび、カウンターの複製技術により、対侵食体戦のパラダイムシフトをもたらしました。</color>","ENG":"<color=#ffd34c>Recently, it's also succeeded in cloning Counters and changed the entire Anti-Corruption warfare paradigm.</color>","TWN":"<color=#ffd34c>最近成功複製制裁者，開始改變侵蝕戰的範例。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이번 프로모션을 통해 제프티 바이오테크가 출시할 상품의 우수성을 감상해 보시길 바랍니다.</color>","JPN":"<color=#ffd34c>ぜひ今回のプロモーションでジェフティ・バイオテクの優秀な新作をご体験ください。</color>","ENG":"<color=#ffd34c>This promotion is to exhibit the company's latest products before their official release. Enjoy!</color>","TWN":"<color=#ffd34c>希望透過此次促銷活動，欣賞一下傑夫堤生物科技即將推出的產品的優越性。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"상자 안에 들어 있길래 설명서인 줄 알았더니...... 순 자화자찬만 써 있군.","JPN":"段ボールに同封されているからマニュアルかと思えば……なんて自画自賛だ、これは。","ENG":"So this letter I found inside the box was not a manual. It's an ad.","TWN":"裝在箱子裡還以爲是說明書呢...... 都是自誇自讚的內容。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그나저나 지금 기술 수준으로는 침식체의 정신 제압도 어림없을 텐데......","JPN":"しかし、今の技術レベルで侵食体の精神制圧なんてまだ難しいはず……","ENG":"By the way, modern technology is no way advanced enough to psychologically dominate C.O.s.","TWN":"不管怎樣，以現在的技術水平，連控制侵蝕體的精神都遠遠不夠......"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"카운터를 복제했다고?","JPN":"しかもカウンターを複製したというのか？","ENG":"Yet they cloned Counters?","TWN":"複製制裁者？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"응. 맞아. 내가 첫째 아인.","JPN":"そうよ。わたしが長女のアイン。","ENG":"Yes, that's right. I'm Eins and I'm the oldest one.","TWN":"嗯，對啊，我是老大:艾茵。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"그리고 난 둘째 츠바이야~","JPN":"ぼくは次女のツヴァイだよ～。","ENG":"And I'm Zwei, the younger one.","TWN":"還有我是老二:茨粨~"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......누가 지은 이름인지 몰라도 참 성의없군.","JPN":"……なんて適当な名前だ。","ENG":"Whoever named you, they didn't try hard enough.","TWN":"......不知道是誰取的名字，令人覺得真沒有誠意。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"너희들끼리 여기까지 온 거니? 상자에 타고?","JPN":"君たち、二人だけでここに来たのかい？　段ボールに入って？","ENG":"Did you come here by yourselves? In this box?","TWN":"只有你們自己來到這裡了嗎？ 坐在箱子？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"아니. 연구소 어른들이 데려다 줬어. 앞으로는 여기서 사는 거라면서.","JPN":"ううん、研究所の大人たちが連れてきてくれたの。わたしたち、これからはここで暮らすんだって。","ENG":"No. The grownups at the lab brought us here. They said this was our new home.","TWN":"不是，是研究所的大人們帶我們來的，說是以後要住在這裡。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"말썽 안 부리고 착하게 굴면 연구소로 안 돌아가도 된댔어.","JPN":"迷惑かけないでいい子にしてれば研究所に戻らなくてもいいって言ってたよ。","ENG":"They said we wouldn't have to come back to the lab if we behaved.","TWN":"如果不惹事，善良乖巧的話，就不用回研究所了。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"츠바이는 말썽 안 부릴 거야. 연구소는 여기도 저기도 전부 똑같아서 지루한걸.","JPN":"ツヴァイはいい子にするよ。研究所は同じ部屋ばかりでつまんないもん。","ENG":"Zwei promises she'll behave. The lab is boring because it looks the same everywhere.","TWN":"茨粨不會惹事的，研究所這裡那裡都一樣覺得很無聊啊。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"그런데 우리 이제 뭐 하고 놀까, 오빠?","JPN":"ねえねえ、これから何して遊ぶ？　お兄ちゃん。","ENG":"By the way, what are we going to do to play now, Brother?","TWN":"不過我們現在要玩什麼呢，哥哥？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......오빠라니, 참 듣기 어색하군.","JPN":"……お兄ちゃんって、慣れない呼ばれ方だな。","ENG":"Brother... It feels awkward to hear that.","TWN":"......怎麼能說是哥哥呢，聽起來有點尷尬。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"응? 왜애? 언니가 상자에서 나오면 착한 오빠가 기다리고 있을 거랬는데?","JPN":"えっ、なんで？　段ボールから出たらやさしいお兄ちゃんが\\n待ってるって、お姉ちゃんから言われたんだもん。","ENG":"Huh? Why? Sister said a good brother would wait for us outside the box.","TWN":"嗯？為什麼啊？姐姐有說從箱子裡出來的話，善良的哥哥會等著我呢？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"앗! 오빠가 아니라 언니였어?","JPN":"もしかして、お兄ちゃんじゃなくてお姉ちゃんなの？","ENG":"Ah! Are you a sister, not a brother?","TWN":"咦！不是哥哥是姐姐嗎？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};